<?php
declare(strict_types=1);

require_once dirname(__DIR__) . '/api/communications/_communications.php';
require_once dirname(__DIR__) . '/api/communications/_delivery.php';
require_once dirname(__DIR__) . '/api/rewards/_zero_value_bridge.php';
require_once __DIR__ . '/merchant-crm.php';
require_once __DIR__ . '/merchant-crm-reward-invites.php';

function mg_crm_bulk_uuid(): string { $b=random_bytes(16);$b[6]=chr((ord($b[6])&15)|64);$b[8]=chr((ord($b[8])&63)|128);return vsprintf('%s%s-%s-%s-%s-%s%s%s',str_split(bin2hex($b),4)); }
function mg_crm_bulk_contact_ids(mixed $value): array { if(!is_array($value))$value=preg_split('/[\s,]+/',(string)$value)?:[];$ids=[];foreach($value as $id){$id=strtolower(trim((string)$id));if($id==='')continue;if(strlen($id)!==36||preg_match('/^[a-f0-9-]{36}$/',$id)!==1)mg_fail('Invalid CRM contact selection.',422);$ids[$id]=$id;} $ids=array_values($ids);if(!$ids)mg_fail('Select at least one CRM contact.',422);if(count($ids)>100)mg_fail('Bulk actions are limited to 100 contacts at a time.',422);return $ids; }
function mg_crm_bulk_idempotency_key(mixed $value,string $prefix,int $merchantId,array $parts=[]): string { $key=trim((string)$value);if($key==='')$key=substr($prefix.':'.hash('sha256',$merchantId.'|'.implode('|',array_map('strval',$parts)).'|'.microtime(true)),0,190);if(mb_strlen($key)>190||preg_match('/^[A-Za-z0-9:._-]+$/',$key)!==1)mg_fail('Invalid bulk action request.',422);return $key; }
function mg_crm_bulk_contacts(PDO $pdo,int $merchantId,array $refs,bool $forUpdate=true): array { $ph=implode(',',array_fill(0,count($refs),'?'));$sql="SELECT cc.*,c.public_id campaign_public_id,c.title campaign_title,c.campaign_type FROM campaign_contacts cc INNER JOIN campaigns c ON c.id=cc.campaign_id WHERE cc.merchant_user_id=? AND cc.public_id IN ($ph)".($forUpdate?' FOR UPDATE':'');$st=$pdo->prepare($sql);$st->execute(array_merge([$merchantId],$refs));$out=[];foreach($st->fetchAll(PDO::FETCH_ASSOC) as $r)$out[(string)$r['public_id']]=$r;return $out; }

function mg_crm_bulk_message_thread(PDO $pdo,array $contact,int $merchantId,int $recipientId): array { $key='crm:'.(string)$contact['public_id'];$st=$pdo->prepare('SELECT id,public_id,conversation_key FROM message_threads WHERE conversation_key=? LIMIT 1 FOR UPDATE');$st->execute([$key]);$thread=$st->fetch(PDO::FETCH_ASSOC);if(!$thread){$public=mg_crm_bulk_uuid();$subject=mb_substr('CRM: '.((string)($contact['name']??'')?: (string)$contact['email']),0,160);$pdo->prepare('INSERT INTO message_threads (public_id,conversation_key,created_by_user_id,subject,created_at,updated_at) VALUES (?,?,?,?,NOW(),NOW())')->execute([$public,$key,$merchantId,$subject]);$thread=['id'=>(int)$pdo->lastInsertId(),'public_id'=>$public,'conversation_key'=>$key];}$pdo->prepare('INSERT IGNORE INTO message_thread_participants (thread_id,user_id,joined_at,last_read_at) VALUES (?,?,NOW(),NOW())')->execute([(int)$thread['id'],$merchantId]);if($recipientId>0)$pdo->prepare('INSERT IGNORE INTO message_thread_participants (thread_id,user_id,joined_at) VALUES (?,?,NOW())')->execute([(int)$thread['id'],$recipientId]);return $thread; }
function mg_crm_bulk_queue_message(PDO $pdo,array $contact,int $merchantId,string $body,string $idem): array { $recipientId=(int)($contact['user_id']??0);$thread=mg_crm_bulk_message_thread($pdo,$contact,$merchantId,$recipientId);$ex=$pdo->prepare('SELECT public_id FROM messages WHERE sender_user_id=? AND idempotency_key=? LIMIT 1 FOR UPDATE');$ex->execute([$merchantId,$idem]);$messageId=(string)($ex->fetchColumn()?:'');$dup=$messageId!=='';if(!$dup){$messageId=mg_crm_bulk_uuid();$pdo->prepare('INSERT INTO messages (public_id,thread_id,sender_user_id,recipient_user_id,body,idempotency_key,source_type,source_reference,created_at) VALUES (?,?,?,?,?,?,?,?,NOW())')->execute([$messageId,(int)$thread['id'],$merchantId,$recipientId>0?$recipientId:null,$body,$idem,'merchant_crm_bulk_message',(string)$contact['public_id']]);$pdo->prepare('UPDATE message_threads SET updated_at=NOW() WHERE id=?')->execute([(int)$thread['id']]);$pdo->prepare('UPDATE message_thread_participants SET last_read_at=NOW() WHERE thread_id=? AND user_id=?')->execute([(int)$thread['id'],$merchantId]);}$via='email_fallback';if(!$dup&&$recipientId>0){mg_create_notification($pdo,$recipientId,'merchant_crm_message','New message from a merchant',$body,'/messages.php?thread='.rawurlencode((string)$thread['public_id']),['actor_user_id'=>$merchantId,'event_key'=>'crm.bulk_message.'.$messageId,'campaign_id'=>(int)$contact['campaign_id'],'contact_id'=>(int)$contact['id'],'thread_id'=>(int)$thread['id'],'message_id'=>$messageId]);$via='microgifter_thread';}elseif(!$dup&&filter_var((string)$contact['email'],FILTER_VALIDATE_EMAIL)){mg_delivery_enqueue($pdo,['idempotency_key'=>'crm-bulk-email:'.$merchantId.':'.$contact['public_id'].':'.$messageId,'event_type'=>'campaign.outbound_email','category'=>'campaign','channel'=>'email','template_key'=>'campaign.merchant_crm_message','recipient_user_id'=>0,'recipient_snapshot'=>['email'=>(string)$contact['email'],'name'=>(string)($contact['name']??'')],'payload'=>['subject'=>'Microgifter merchant message','text'=>$body,'message_type'=>'merchant_crm_bulk_message','thread_id'=>(string)$thread['public_id'],'message_id'=>$messageId],'max_attempts'=>3]);}mg_merchant_crm_record_event($pdo,['merchant_user_id'=>$merchantId,'campaign_id'=>(int)$contact['campaign_id'],'campaign_type'=>(string)$contact['campaign_type'],'event_type'=>'crm.message.sent','source_type'=>'merchant_crm_bulk_message','source_public_id'=>(string)$contact['public_id'],'user_id'=>$recipientId>0?$recipientId:null,'email'=>(string)$contact['email'],'name'=>(string)($contact['name']??''),'metadata'=>['thread_id'=>(string)$thread['public_id'],'message_id'=>$messageId,'duplicate'=>$dup]]);return ['contact_id'=>(string)$contact['public_id'],'status'=>$dup?'duplicate':'sent','thread_id'=>(string)$thread['public_id'],'message_id'=>$messageId,'delivered_via'=>$via,'duplicate'=>$dup]; }

function mg_crm_bulk_reward_expiry(array $t): ?string { $r=(string)($t['expiration_rule']??'none');if(($r==='fixed_date'||$r==='event_date')&&!empty($t['expires_at']))return (string)$t['expires_at'];if($r==='after_issue'&&!empty($t['expiration_days']))return date('Y-m-d H:i:s',time()+((int)$t['expiration_days']*86400));return null; }
function mg_crm_bulk_campaign_event(PDO $pdo,array $contact,?int $walletId,string $type,array $context=[]): void { $pdo->prepare('INSERT INTO campaign_events (public_id,merchant_user_id,campaign_id,wallet_item_id,contact_id,event_type,event_context_json,created_at) VALUES (?,?,?,?,?,?,?,NOW())')->execute([mg_crm_bulk_uuid(),(int)$contact['merchant_user_id'],(int)$contact['campaign_id'],$walletId,(int)$contact['id'],$type,json_encode($context,JSON_UNESCAPED_SLASHES|JSON_UNESCAPED_UNICODE)]); }
function mg_crm_bulk_template(PDO $pdo,int $merchantId,string $ref): array { $st=$pdo->prepare("SELECT * FROM reward_templates WHERE public_id=? AND merchant_user_id=? AND status='active' LIMIT 1 FOR UPDATE");$st->execute([$ref,$merchantId]);$t=$st->fetch(PDO::FETCH_ASSOC);if(!$t)throw new RuntimeException('Active reward template not found.');return $t; }
function mg_crm_bulk_assert_template_inventory(PDO $pdo,array $template,bool $includePendingInvites=false): void { if($template['quantity_limit']===null)return;$reserved=(int)$template['issued_count'];if($includePendingInvites&&mg_crm_reward_invites_ready($pdo)){$st=$pdo->prepare("SELECT COUNT(*) FROM crm_reward_invites WHERE reward_template_id=? AND status='sent' AND (expires_at IS NULL OR expires_at>NOW())");$st->execute([(int)$template['id']]);$reserved+=(int)$st->fetchColumn();}if($reserved>=(int)$template['quantity_limit'])throw new RuntimeException('Reward template limit has been reached.'); }
function mg_crm_bulk_issue_direct_reward(PDO $pdo,array $contact,array $template,int $merchantId,string $note,string $idem): array { if((int)($contact['user_id']??0)<=0)throw new RuntimeException('Customer account required before sending a direct CRM reward.');mg_crm_bulk_assert_template_inventory($pdo,$template,false);$ex=$pdo->prepare("SELECT public_id FROM wallet_items WHERE merchant_user_id=? AND source_type='manual_send' AND source_id=? AND JSON_UNQUOTE(JSON_EXTRACT(metadata_json,'$.crm_idempotency_key'))=? LIMIT 1");$ex->execute([$merchantId,(string)$contact['public_id'],$idem]);$old=(string)($ex->fetchColumn()?:'');if($old!=='')return ['contact_id'=>(string)$contact['public_id'],'status'=>'duplicate','wallet_item_id'=>$old,'duplicate'=>true];$dupe=$pdo->prepare("SELECT public_id FROM wallet_items WHERE merchant_user_id=? AND contact_id=? AND reward_template_id=? AND source_type='manual_send' AND status IN ('issued','viewed','claimed','redeemed') AND (expires_at IS NULL OR expires_at>NOW()) ORDER BY id DESC LIMIT 1");$dupe->execute([$merchantId,(int)$contact['id'],(int)$template['id']]);$dupeId=(string)($dupe->fetchColumn()?:'');if($dupeId!=='')return ['contact_id'=>(string)$contact['public_id'],'status'=>'skipped','reason'=>'active_duplicate','wallet_item_id'=>$dupeId,'duplicate'=>true];$recent=$pdo->prepare("SELECT COUNT(*) FROM wallet_items WHERE merchant_user_id=? AND contact_id=? AND source_type='manual_send' AND created_at>(NOW() - INTERVAL 10 MINUTE)");$recent->execute([$merchantId,(int)$contact['id']]);if((int)$recent->fetchColumn()>0)return ['contact_id'=>(string)$contact['public_id'],'status'=>'skipped','reason'=>'cooldown'];$expires=mg_crm_bulk_reward_expiry($template);$wallet=mg_crm_bulk_uuid();$meta=['campaign_type'=>'merchant_crm_direct_gift','original_campaign_type'=>(string)$contact['campaign_type'],'crm_contact_id'=>(string)$contact['public_id'],'campaign_public_id'=>(string)$contact['campaign_public_id'],'reward_template_id'=>(string)$template['public_id'],'note'=>$note,'crm_idempotency_key'=>$idem,'bulk_action'=>true];$pdo->prepare('INSERT INTO wallet_items (public_id,user_id,contact_id,merchant_user_id,reward_template_id,campaign_id,source_type,source_id,status,value_cents_snapshot,currency_snapshot,title_snapshot,metadata_json,issued_at,expires_at,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,NOW(),?,NOW(),NOW())')->execute([$wallet,(int)$contact['user_id'],(int)$contact['id'],$merchantId,(int)$template['id'],(int)$contact['campaign_id'],'manual_send',(string)$contact['public_id'],'issued',(int)$template['value_amount_cents'],(string)$template['currency'],(string)$template['title'],json_encode($meta,JSON_UNESCAPED_SLASHES|JSON_UNESCAPED_UNICODE),$expires]);$walletDb=(int)$pdo->lastInsertId();$pdo->prepare('UPDATE reward_templates SET issued_count=issued_count+1,updated_at=NOW() WHERE id=?')->execute([(int)$template['id']]);$bridge=mg_zero_reward_issue_from_wallet($pdo,['merchant_user_id'=>(int)$contact['merchant_user_id'],'recipient_user_id'=>(int)$contact['user_id'],'recipient_external_id'=>(string)$contact['public_id'],'wallet_item_db_id'=>$walletDb,'wallet_item_public_id'=>$wallet,'campaign_public_id'=>(string)$contact['campaign_public_id'],'reward_template_public_id'=>(string)$template['public_id'],'source_type'=>'merchant_crm_bulk_gift','source_reference'=>$wallet,'source_line_reference'=>(string)$contact['public_id'],'title'=>(string)$template['title'],'description'=>$template['description']??null,'currency'=>(string)$template['currency'],'display_value_cents'=>(int)$template['value_amount_cents'],'expires_at'=>$expires,'redemption_instructions'=>$template['redemption_instructions']??null,'terms'=>['campaign_type'=>'merchant_crm_direct_gift','original_campaign_type'=>(string)$contact['campaign_type'],'note'=>$note,'bulk_action'=>true]]);mg_crm_bulk_campaign_event($pdo,$contact,$walletDb,'crm.gift.issued',['wallet_item_id'=>$wallet,'reward_template_id'=>(string)$template['public_id'],'pppm_bridge'=>$bridge,'bulk_action'=>true]);mg_merchant_crm_record_event($pdo,['merchant_user_id'=>$merchantId,'campaign_id'=>(int)$contact['campaign_id'],'campaign_type'=>'merchant_crm_direct_gift','event_type'=>'crm.gift.issued','source_type'=>'merchant_crm_bulk_gift','source_public_id'=>(string)$contact['public_id'],'user_id'=>(int)$contact['user_id'],'email'=>(string)$contact['email'],'name'=>(string)($contact['name']??''),'value_cents'=>(int)$template['value_amount_cents'],'metadata'=>['wallet_item_id'=>$wallet,'reward_template_id'=>(string)$template['public_id'],'bulk_action'=>true]]);return ['contact_id'=>(string)$contact['public_id'],'status'=>'issued','wallet_item_id'=>$wallet,'expires_at'=>$expires,'duplicate'=>false]; }
function mg_crm_bulk_send_reward_invite(PDO $pdo,array $contact,array $template,int $merchantId,string $note,string $idem): array { if((int)($contact['user_id']??0)>0)throw new RuntimeException('This contact already has an account. Use direct reward send.');if(!mg_crm_reward_invites_ready($pdo))throw new RuntimeException('CRM reward invite schema is not installed.');$email=strtolower(trim((string)($contact['email']??'')));if(!filter_var($email,FILTER_VALIDATE_EMAIL))return ['contact_id'=>(string)$contact['public_id'],'status'=>'skipped','reason'=>'missing_valid_email'];mg_crm_bulk_assert_template_inventory($pdo,$template,true);$ex=$pdo->prepare('SELECT public_id FROM crm_reward_invites WHERE merchant_user_id=? AND idempotency_key=? LIMIT 1');$ex->execute([$merchantId,$idem]);$old=(string)($ex->fetchColumn()?:'');if($old!=='')return ['contact_id'=>(string)$contact['public_id'],'status'=>'duplicate','invite_id'=>$old,'duplicate'=>true];$active=$pdo->prepare("SELECT public_id FROM crm_reward_invites WHERE merchant_user_id=? AND contact_id=? AND reward_template_id=? AND status='sent' AND (expires_at IS NULL OR expires_at>NOW()) LIMIT 1");$active->execute([$merchantId,(int)$contact['id'],(int)$template['id']]);$activeId=(string)($active->fetchColumn()?:'');if($activeId!=='')return ['contact_id'=>(string)$contact['public_id'],'status'=>'skipped','reason'=>'invite_pending','invite_id'=>$activeId,'duplicate'=>true];$invite=mg_crm_reward_invite_uuid();$exp=date('Y-m-d H:i:s',time()+1209600);$url=mg_app_base_url().'/signup.php?crm_reward_invite='.rawurlencode($invite);$meta=['campaign_type'=>'merchant_crm_reward_invite','contact_id'=>(string)$contact['public_id'],'reward_template_id'=>(string)$template['public_id'],'bulk_action'=>true];$pdo->prepare('INSERT INTO crm_reward_invites (public_id,merchant_user_id,campaign_id,contact_id,reward_template_id,email,name,status,note,idempotency_key,invite_url,sent_at,expires_at,metadata_json,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW(),NOW())')->execute([$invite,$merchantId,(int)$contact['campaign_id'],(int)$contact['id'],(int)$template['id'],$email,(string)($contact['name']??''),'sent',$note,$idem,$url,date('Y-m-d H:i:s'),$exp,json_encode($meta,JSON_UNESCAPED_SLASHES|JSON_UNESCAPED_UNICODE)]);try{$delivery=mg_delivery_enqueue($pdo,['idempotency_key'=>'crm-bulk-reward-invite-email:'.$idem,'event_type'=>'campaign.outbound_email','category'=>'campaign','channel'=>'email','template_key'=>'campaign.crm_reward_invite','recipient_snapshot'=>['email'=>$email,'name'=>(string)($contact['name']??'')],'payload'=>mg_crm_reward_invite_email_payload($contact,$template,$invite,$url,$note,$exp),'max_attempts'=>3]);}catch(Throwable){$delivery=['queued'=>false];}$eventContact=$contact;$eventContact['contact_id']=(int)$contact['id'];mg_crm_reward_invite_record_campaign_event($pdo,$eventContact,null,'crm.reward_invite.sent',['invite_id'=>$invite,'reward_template_id'=>(string)$template['public_id'],'email_delivery'=>$delivery,'bulk_action'=>true]);mg_merchant_crm_record_event($pdo,['merchant_user_id'=>$merchantId,'campaign_id'=>(int)$contact['campaign_id'],'campaign_type'=>'merchant_crm_reward_invite','event_type'=>'crm.reward_invite.sent','source_type'=>'merchant_crm_bulk_reward_invite','source_public_id'=>(string)$contact['public_id'],'email'=>$email,'name'=>(string)($contact['name']??''),'value_cents'=>(int)$template['value_amount_cents'],'metadata'=>['invite_id'=>$invite,'reward_template_id'=>(string)$template['public_id'],'delivery'=>$delivery,'bulk_action'=>true]]);return ['contact_id'=>(string)$contact['public_id'],'status'=>'invited','invite_id'=>$invite,'invite_url'=>$url,'expires_at'=>$exp,'duplicate'=>false]; }
function mg_crm_bulk_result_summary(array $results): array { $s=['selected'=>count($results),'sent'=>0,'issued'=>0,'invited'=>0,'skipped'=>0,'failed'=>0,'duplicates'=>0];foreach($results as $r){$status=(string)($r['status']??'');if(isset($s[$status]))$s[$status]++;if(!empty($r['duplicate']))$s['duplicates']++;}return $s; }
